function check_updatePauseDuration_reverts_when_paused(uint128 newPauseDuration, uint128 currentPauseStart, uint128 currentPauseDuration) public {
    // Setup: contract is paused
    vm.assume(currentPauseStart != 0);
    vm.assume(block.timestamp < currentPauseStart + currentPauseDuration);
    _setPauseTime(currentPauseStart);
    pauseDuration = currentPauseDuration;

    // Precondition: contract is paused
    assert(paused());

    // Action: attempt to update pause duration
    // This should revert when paused, but currently it doesn't
    try this._updatePauseDuration(newPauseDuration) {
        // If we reach here, the function did not revert - BUG
        assert(false);
    } catch {
        // Expected: should revert when paused
        assert(true);
    }
}
